// TestNovelLogHelpWires smoke-tests that the log command resolves at runtime
// and renders --help without error.
func TestNovelLogHelpWires(t *testing.T) {
	cmd := RootCmd()
	cmd.SetArgs([]string{"log", "--help"})
	cmd.SetOut(io.Discard)
	cmd.SetErr(io.Discard)
	if err := cmd.Execute(); err != nil {
		t.Fatalf("log --help error = %v (novel command not wired correctly?)", err)
	}
}

func TestNovelLogBuildActivityBody(t *testing.T) {
	ref := entityRef{Type: "opportunity", ID: 88}
	body := buildActivityBody(ref, "Left voicemail", 3)

	parent, ok := body["parent"].(map[string]any)
	if !ok || parent["type"] != "opportunity" || parent["id"] != int64(88) {
		t.Errorf("parent = %#v, want {opportunity 88}", body["parent"])
	}
	typ, ok := body["type"].(map[string]any)
	if !ok || typ["category"] != "user" || typ["id"] != 3 {
		t.Errorf("type = %#v, want {user 3}", body["type"])
	}
	if body["details"] != "Left voicemail" {
		t.Errorf("details = %#v", body["details"])
	}
	if _, ok := body["activity_date"]; !ok {
		t.Error("activity_date missing")
	}
}

func TestNovelLogMatchActivityType(t *testing.T) {
	// Keyed-by-category shape.
	keyed := json.RawMessage(`{"user":[{"id":3,"name":"Phone Call"},{"id":4,"name":"Meeting"}],"system":[{"id":0,"name":"Note"}]}`)
	if id, ok := matchActivityType(keyed, "phone call"); !ok || id != 3 {
		t.Errorf("matchActivityType(keyed, phone call) = %d,%v, want 3,true", id, ok)
	}
	// Flat-array shape.
	flat := json.RawMessage(`[{"id":7,"name":"Demo"}]`)
	if id, ok := matchActivityType(flat, "Demo"); !ok || id != 7 {
		t.Errorf("matchActivityType(flat, Demo) = %d,%v, want 7,true", id, ok)
	}
	if _, ok := matchActivityType(flat, "nope"); ok {
		t.Error("matchActivityType should miss on unknown name")
	}
}

// TestNovelLogPreviewNoNetwork verifies the default path previews and exits 0
// without network, even under the verifier.
func TestNovelLogPreviewNoNetwork(t *testing.T) {
	t.Setenv(cliutil.VerifyEnvVar, "1")
	cmd := RootCmd()
	var out bytes.Buffer
	cmd.SetArgs([]string{"log", "call", "--on", "opportunity:88", "--note", "Left voicemail"})
	cmd.SetOut(&out)
	cmd.SetErr(io.Discard)
	if err := cmd.Execute(); err != nil {
		t.Fatalf("log preview error = %v", err)
	}
	if !strings.Contains(out.String(), "PREVIEW") {
		t.Errorf("preview output missing PREVIEW marker: %q", out.String())
	}
}

